package genxsolution.vms.vmsbackend.vehicle_management.vehicle_manufacturer.service;
import genxsolution.vms.vmsbackend.vehicle_management.exception.VehicleResourceNotFoundException; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_manufacturer.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_manufacturer.mapper.VehicleManufacturerMapper; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_manufacturer.repository.VehicleManufacturerRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleManufacturerService { private final VehicleManufacturerRepository repository; private final VehicleManufacturerMapper mapper; public VehicleManufacturerService(VehicleManufacturerRepository repository,VehicleManufacturerMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleManufacturerResponse> list(){ return repository.findAll().stream().map(mapper::toResponse).toList(); } public VehicleManufacturerResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleManufacturer", id.toString())); } public VehicleManufacturerResponse create(VehicleManufacturerUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleManufacturerResponse update(UUID id,VehicleManufacturerUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleManufacturer", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new VehicleResourceNotFoundException("VehicleManufacturer", id.toString()); } }
